from slack_bolt import App
from anthropic import Anthropic
import os, json, threading

app = App(token=os.environ["SLACK_BOT_TOKEN"])
client = Anthropic()

TOOLS = [
    {
        "name": "create_jira_ticket",
        "description": "Create a Jira ticket with a title and description.",
        "input_schema": {
            "type": "object",
            "properties": {
                "title": {"type": "string"},
                "description": {"type": "string"},
                "priority": {"type": "string", "enum": ["Low", "Medium", "High", "Critical"]},
            },
            "required": ["title", "description", "priority"],
        },
    },
    {
        "name": "get_oncall",
        "description": "Return the name of the current on-call engineer for a given team.",
        "input_schema": {
            "type": "object",
            "properties": {"team": {"type": "string"}},
            "required": ["team"],
        },
    },
]

def execute_tool(name: str, inputs: dict) -> str:
    if name == "create_jira_ticket":
        # Real implementation calls the Jira REST API
        return json.dumps({"ticket_id": "OPS-1042", "url": "https://jira.example.com/OPS-1042"})
    if name == "get_oncall":
        return json.dumps({"team": inputs["team"], "oncall": "Alice Chen", "phone": "+1-555-0100"})
    return "Unknown tool"

def run_agent_with_tools(text: str, say, thread_ts: str) -> None:
    messages = [{"role": "user", "content": text}]

    while True:
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=600,
            tools=TOOLS,
            system="You are a helpful ops bot. Use tools to take real actions when asked.",
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            reply = next((b.text for b in response.content if b.type == "text"), "Done.")
            say(text=reply, thread_ts=thread_ts)
            break

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = execute_tool(block.name, block.input)
                    tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
            messages.append({"role": "assistant", "content": response.content})
            messages.append({"role": "user", "content": tool_results})
        else:
            break

@app.event("app_mention")
def handle_mention(event, say):
    text = event["text"]
    thread_ts = event.get("thread_ts") or event["ts"]
    threading.Thread(target=run_agent_with_tools, args=(text, say, thread_ts), daemon=True).start()

from slack_bolt import App
from slack_sdk import WebClient
import os, json

app = App(token=os.environ["SLACK_BOT_TOKEN"])
web = WebClient(token=os.environ["SLACK_BOT_TOKEN"])

def send_approval_request(channel: str, thread_ts: str, action_summary: str, action_id: str) -> None:
    """Ask the user to approve an agent action before executing it.""""
    web.chat_postMessage(
        channel=channel,
        thread_ts=thread_ts,
        blocks=[
            {
                "type": "section",
                "text": {
                    "type": "mrkdwn",
                    "text": f"*Agent wants to take the following action:*\n{action_summary}"
                }
            },
            {
                "type": "actions",
                "elements": [
                    {
                        "type": "button",
                        "text": {"type": "plain_text", "text": "Approve"},
                        "style": "primary",
                        "action_id": f"approve_{action_id}",
                        "value": action_id,
                    },
                    {
                        "type": "button",
                        "text": {"type": "plain_text", "text": "Reject"},
                        "style": "danger",
                        "action_id": f"reject_{action_id}",
                        "value": action_id,
                    },
                ]
            }
        ]
    )

@app.action("approve_create_ticket")
def handle_approve(ack, body, say):
    ack()
    channel = body["channel"]["id"]
    thread_ts = body["message"]["thread_ts"]
    # Execute the deferred action
    say(text=":white_check_mark: Ticket created: OPS-1042", thread_ts=thread_ts)

@app.action("reject_create_ticket")
def handle_reject(ack, body, say):
    ack()
    thread_ts = body["message"]["thread_ts"]
    say(text=":x: Action cancelled.", thread_ts=thread_ts)
